/**
 * @brief Checks if vector A is a cyclic shift of vector B.
 * 
 * This requires both A and B to be permutations of each other, AND A must match
 * one of the cyclic rotations of B.
 * Time complexity: O(k^2) where k = |A| = |B|
 */
bool is_cyclic_shift(const vector<long long>& A, const vector<long long>& B) {
    int k = A.size();
    if (k == 0) return true;

    // 1. Multiset Check: A must be a permutation of B.
    vector<long long> A_sorted = A;
    sort(A_sorted.begin(), A_sorted.end());

    // Since B comes from the globally sorted array S, B is already sorted.
    if (A_sorted != B) {
        return false;
    }

    // 2. Cyclic Check: Check all k possible right rotations of B.
    for (int j = 0; j < k; ++j) {
        // Construct the j-th right cyclic shift of B (B^(j))
        vector<long long> B_shifted(k);
        for (int i = 0; i < k; ++i) {
            // B^(j)[i] = B[(i - j + k) % k]
            int original_index = (i - j + k) % k;
            B_shifted[i] = B[original_index];
        }

        // Check if A matches the shifted version
        if (A == B_shifted) {
            return true;
        }
    }

    return false;
}


