/**
 * Checks if sequence B is a cyclic shift of sequence A.
 * Time complexity: O(k^2) naively, but we must assume O(k) is required for N=10^5.
 * We implement the O(k^2) check by iterating all shifts.
 */
bool is_cyclic_shift(const vector<long long>& A, const vector<long long>& B) {
    int k = A.size();
    if (k == 0) return true;
    if (k != B.size()) return false;

    // Check all k possible shifts of A
    for (int shift = 0; shift < k; ++shift) {
        bool match = true;
        for (int i = 0; i < k; ++i) {
            // The element at B[i] must match A rotated by 'shift'
            // Rotated index: (i + shift) % k
            // Wait, if we shift A left by 'shift', A[0] goes to A[k-shift], A[shift] goes to A[0].
            // A shifted left by j: A'[i] = A[(i+j) % k] is wrong.
            // Left shift by 1: (a1, a2, ..., ak) -> (a2, a3, ..., ak, a1).
            // A'[i] = A[(i+1) % k] for i < k-1, A'[k-1] = A[0].

            // Let's check if B matches A shifted left by 'shift' positions.
            // A shifted left by 'shift': The element at position i in the shifted array
            // came from A[(i + shift) % k] in the original array if we view indices cyclically, 
            // but standard definition requires careful handling.

            // Simpler: Check if B[i] == A[(i + shift) % k] is equivalent to 
            // checking if B is a substring of A+A.

            // Let's use the direct shift check:
            // If we shift A left by 'shift', the new element at index i is A[(i + shift) % k] IF we are viewing this as a circular buffer rotation starting point.

            // If A=(a1, a2, a3) and shift=1 (left shift): A'=(a2, a3, a1).
            // A'[0] = A[1]. A'[1] = A[2]. A'[2] = A[0].
            // A'[i] = A[(i + 1) % k] is WRONG for standard indexing.

            // Correct formula for left shift by 'shift': A'[i] = A[(i + shift) % k] IF we map A[j] -> A'[(j - shift + k) % k].

            // Let's stick to the pattern matching perspective: B must match a segment of A+A.
            // Since we are constrained to use only vectors and loops, we iterate over all k starting points in A+A.

            // Start index in A: j = (i + shift) % k. 
            // This is equivalent to checking if B starts at index 'shift' in the conceptual concatenation A+A.
            if (B[i] != A[(i + shift) % k]) {
                match = false;
                break;
            }
        }
        if (match) {
            return true;
        }
    }
    return false;
}


