// Function to compute the Longest Proper Prefix which is also a Suffix (LPS) array for KMP
vector<int> compute_lps(const vector<long long>& pattern) {
    int m = pattern.size();
    vector<int> lps(m, 0);
    int length = 0; // length of the previous longest prefix suffix
    int i = 1;

    while (i < m) {
        if (pattern[i] == pattern[length]) {
            length++;
            lps[i] = length;
            i++;
        } else {
            if (length != 0) {
                length = lps[length - 1];
            } else {
                lps[i] = 0;
                i++;
            }
        }
    }
    return lps;
}

// Function to check if pattern P is a substring of text T using KMP
// Since we only care if it exists, we return true/false.
bool kmp_search(const vector<long long>& text, const vector<long long>& pattern) {
    int n = text.size();
    int m = pattern.size();

    if (m == 0) return true;
    if (n < m) return false;

    vector<int> lps = compute_lps(pattern);

    int i = 0; // index for text
    int j = 0; // index for pattern

    while (i < n) {
        if (pattern[j] == text[i]) {
            i++;
            j++;
        }

        if (j == m) {
            // Pattern found
            return true;
            // For finding all occurrences: 
            // j = lps[j - 1]; 
        } else if (i < n && pattern[j] != text[i]) {
            if (j != 0) {
                j = lps[j - 1];
            } else {
                i++;
            }
        }
    }
    return false;
}


